export default function DewanTradersLogo({
  className = "",
  width = 360,
  autoplay = true,
  iconOnly = false,
}: {
  className?: string;
  width?: number;
  autoplay?: boolean;
  iconOnly?: boolean;
}) {
  const svgRef = useRef<SVGSVGElement>(null);
  const outlineRef = useRef<SVGPathElement>(null);
  const fillRef = useRef<SVGGElement>(null);
  const eagleGroupRef = useRef<SVGGElement>(null);
  const textRef = useRef<SVGGElement>(null);

  const runAnimation = async () => {
    const { animate, svg, stagger } = await import("animejs");

    const outline = outlineRef.current;
    const fill = fillRef.current;
    const text = textRef.current;
    const eagleGroup = eagleGroupRef.current;

    if (!outline || !fill || !eagleGroup) return;

    // Reset state
    fill.style.opacity = "0";
    if (text) {
      text.style.opacity = "0";
      (text as unknown as SVGGElement).style.transform = "translateY(6px)";
    }
    eagleGroup.style.opacity = "1";
    eagleGroup.style.transform = "translateY(-46px) scale(0.72)";

    const drawable = svg.createDrawable(outline);

    // 1) Eagle silhouette draws itself in (stroke reveal)
    animate(eagleGroup, {
      translateY: [-46, 0],
      scale: [0.72, 1],
      duration: 900,
      easing: "easeOutQuad",
    });

    animate(drawable, {
      draw: ["0 0", "0 1"],
      duration: 1100,
      easing: "easeInOutSine",
      onComplete: () => {
        // 2) Full-color traced artwork fades in over the outline
        animate(fill, {
          opacity: [0, 1],
          duration: 500,
          easing: "easeOutQuad",
        });
        // 3) Outline stroke fades out, having done its job
        animate(outline, {
          opacity: [1, 0],
          duration: 500,
          easing: "easeOutQuad",
        });
        // 4) Wordmark fades/slides in on top, always fully legible
        if (text) {
          animate(text, {
            opacity: [0, 1],
            translateY: [6, 0],
            duration: 700,
            delay: 150,
            easing: "easeOutQuad",
            onComplete: () => {
              // 5) Gentle continuous idle motion so it reads as "alive" as a
              //    persistent site logo, not just a one-shot intro
              animate(eagleGroup, {
                translateY: [0, -4, 0],
                duration: 4200,
                easing: "easeInOutSine",
                loop: true,
              });
            },
          });
        } else {
          // If no text, run idle motion directly on eagleGroup
          animate(eagleGroup, {
            translateY: [0, -4, 0],
            duration: 4200,
            easing: "easeInOutSine",
            loop: true,
          });
        }
      },
    });
  };

  useEffect(() => {
    if (!autoplay) return;
    const t = setTimeout(() => {
      runAnimation();
    }, 250);
    return () => clearTimeout(t);
  }, [autoplay]);

  return (
    <div className={className} style={{ width, maxWidth: "100%" }}>
      <svg
        ref={svgRef}
        viewBox={iconOnly ? "0 0 670 430" : "0 0 670 620"}
        style={{ width: "100%", height: "auto", overflow: "visible", cursor: "pointer" }}
        onClick={runAnimation}
      >
        <defs>
          <clipPath id="eagleClip">
            <rect x="0" y="0" width="670" height="430" />
          </clipPath>
        </defs>

        {/* EAGLE MARK */}
        <g ref={eagleGroupRef} style={{ transformOrigin: "335px 215px", transformBox: "fill-box" as any }}>
          {/* Full-color traced fill (revealed after the outline draws in) */}
          <g ref={fillRef} clipPath="url(#eagleClip)">
            {eaglePaths.map(([d, fill, transform], i) => (
              <path key={i} d={d} fill={fill} transform={transform} />
            ))}
          </g>

          {/* Single-stroke outline used for the draw-in animation */}
          <path
            ref={outlineRef}
            d={eagleOutline}
            fill="none"
            stroke="#16324a"
            strokeWidth={3}
            strokeLinejoin="round"
            strokeLinecap="round"
          />
        </g>

        {/* WORDMARK - real SVG text (crisp, accessible, always legible on its own) */}
        {!iconOnly && (
          <g ref={textRef} style={{ transformOrigin: "335px 500px" }}>
            <text
              x="335"
              y="500"
              textAnchor="middle"
              fontFamily="Georgia, 'Times New Roman', serif"
              fontWeight={700}
              fontSize={78}
              letterSpacing={2}
              fill="#000000"
            >
              DEWAN
            </text>
            <text
              x="335"
              y="538"
              textAnchor="middle"
              fontFamily="Arial, Helvetica, sans-serif"
              fontWeight={500}
              fontSize={22}
              letterSpacing={9}
              fill="#111111"
            >
              TRADERS
            </text>
          </g>
        )}
      </svg>
    </div>
  );
}